def get_palette(name):
    return globals().get(name.upper(), [])

# -----------------------------------------------------------------------------
# Style Loader Helper
# -----------------------------------------------------------------------------
import matplotlib.pyplot as plt
import os

def use_style(style_name):
    """
    Load a Matplotlib style by name from the local mplstyles directory.
    
    Args:
        style_name (str): Name of the style (e.g., 'nature', 'ieee', 'science', 'vibrant', 'high-contrast')
    """
    # Get the directory of this script
    base_dir = os.path.dirname(os.path.abspath(__file__))
    
    # Define possible paths
    journal_path = os.path.join(base_dir, '样式配置文件', '期刊样式', f'{style_name}.mplstyle')
    color_path = os.path.join(base_dir, '样式配置文件', '颜色样式', f'{style_name}.mplstyle')
    
    if os.path.exists(journal_path):
        plt.style.use(journal_path)
        print(f"Successfully loaded journal style: {style_name}")
    elif os.path.exists(color_path):
        plt.style.use(color_path)
        print(f"Successfully loaded color style: {style_name}")
    else:
        print(f"Warning: Style '{style_name}' not found in {base_dir}/样式配置文件/")
        print("Available styles:")
        print("  Journals:", [f.replace('.mplstyle','') for f in os.listdir(os.path.join(base_dir, '样式配置文件', '期刊样式')) if f.endswith('.mplstyle')])
        print("  Colors:", [f.replace('.mplstyle','') for f in os.listdir(os.path.join(base_dir, '样式配置文件', '颜色样式')) if f.endswith('.mplstyle')])

def use_nature_style():
    """Shortcut to load Nature journal style + NPG colors"""
    use_style('nature')
    # Set default color cycle to NPG
    plt.rcParams['axes.prop_cycle'] = plt.cycler(color=NPG_NRC)

def use_science_style():
    """Shortcut to load Science journal style + AAAS colors"""
    # Note: SciencePlots doesn't have a 'science.mplstyle' in the journals folder by default in all versions,
    # but let's check standard ones. If 'science' exists in journals, use it.
    use_style('ieee') # IEEE is a good standard fallback if science is missing, or use 'nature'
    plt.rcParams['axes.prop_cycle'] = plt.cycler(color=AAAS_DEFAULT)
